INSERT INTO `config_info` VALUES (1,'application-dev.yml','DEFAULT_GROUP','# 配置文件加密根密码\njasypt:\n  encryptor:\n    password: pig\n    algorithm: PBEWithMD5AndDES\n    iv-generator-classname: org.jasypt.iv.NoIvGenerator\n    \n# Spring 相关\nspring:\n  cache:\n    type: redis\n  data:\n    redis:\n      host: ${REDIS_HOST:127.0.0.1}\n      password: ${REDIS_PASSWORD:}\n      port: ${REDIS_PORT:6379}\n      database: ${REDIS_DATABASE:0}\n  cloud:\n    sentinel:\n      eager: true\n      transport:\n        dashboard: pig-sentinel:5003\n    openfeign:\n      sentinel:\n        enabled: true\n      okhttp:\n        enabled: true\n      httpclient:\n        enabled: false\n      compression:\n        request:\n          enabled: true\n        response:\n          enabled: true\n\n# 暴露监控端点\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: \"*\"  \n  endpoint:\n    health:\n      show-details: ALWAYS\n\n# mybaits-plus配置\nmybatis-plus:\n  mapper-locations: classpath:/mapper/*Mapper.xml\n  global-config:\n    banner: false\n    db-config:\n      id-type: auto\n      table-underline: true\n      logic-delete-value: 1\n      logic-not-delete-value: 0\n  type-handlers-package: com.pig4cloud.pig.common.mybatis.handler\n  configuration:\n    map-underscore-to-camel-case: true\n    shrink-whitespaces-in-sql: true\n\n# 短信插件配置：https://www.yuque.com/vxixfq/pig/zw8udk\nsms:\n  is-print: false # 是否打印日志\n  config-type: yaml # 配置类型，yaml\n\npig:\n  outbox:\n    mode: microservice\n    kafka:\n      bootstrap-servers: \"127.0.0.1:9093\"\n      acks: all\n      retries: 3\n      max-in-flight-requests-per-connection: 5\n      enable-idempotence: true\n    consumer:\n      enabled: true\n      bootstrap-servers: \"127.0.0.1:9093\"\n      domains: [\"order\", \"vault\", \"market\"]\n      auto-offset-reset: \"earliest\"\n      enable-auto-commit: false\n      max-poll-records: 100\n      concurrency: 3','daa69c03849cd62d4864165c10796a31','2025-05-16 12:48:39','2026-01-24 21:44:54','nacos','192.168.155.1','','public','',NULL,NULL,'yaml',NULL,''),(2,'pig-auth-dev.yml','DEFAULT_GROUP','# 数据源\nspring:\n  freemarker:\n    allow-request-override: false\n    allow-session-override: false\n    cache: true\n    charset: UTF-8\n    check-template-location: true\n    content-type: text/html\n    enabled: true\n    request-context-attribute: request\n    expose-request-attributes: false\n    expose-session-attributes: false\n    expose-spring-macro-helpers: true\n    prefer-file-system-access: true\n    suffix: .ftl\n    template-loader-path: classpath:/templates/\n\n\nsecurity:\n  encode-key: \'thanks,pig4cloud\'\n  ignore-clients:\n    - test\n    - client\n    - open\n    - app','b4a660ece61e8180b4940a0770eddfee','2025-01-30 16:50:04','2026-01-23 08:56:50','nacos','192.168.155.1','','public',NULL,NULL,NULL,'yaml',NULL,''),(3,'pig-codegen-dev.yml','DEFAULT_GROUP','# 数据源配置\nspring:\n  datasource:\n    type: com.zaxxer.hikari.HikariDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    username: ${MYSQL_USERNAME:root}\n    password: ${MYSQL_PASSWORD:root}\n    url: jdbc:mysql://${MYSQL_HOST:127.0.0.1}:${MYSQL_PORT:3306}/${MYSQL_DB:pig}?characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=false&allowMultiQueries=true&useJDBCCompliantTimezoneShift=true&useLegacyDatetimeCode=false&serverTimezone=Asia/Shanghai&nullCatalogMeansCurrent=true&allowPublicKeyRetrieval=true\n  resources:\n    static-locations: classpath:/static/,classpath:/views/\n','a1e1ae7127517eae96a2df8b15d94fe3','2025-10-29 11:39:40','2025-10-29 11:39:40','nacos','10.25.25.2','','public','',NULL,NULL,'yaml',NULL,''),(4,'pig-gateway-dev.yml','DEFAULT_GROUP','management:\n    endpoints:\n      web:\n        exposure:\n          include: \"*\"\n    endpoint:\n      gateway:\n        enabled: true\nspring:                                                                                                                                                                                                                                                                    \n    cloud:                                                                                                                                                                                                                                                                   \n      gateway:\n        routes:                                                                                                                                                                                                                                                          \n          # 认证中心                                                                                                                                                                                                                                                     \n          - id: pig-auth                                                                                                                                                                                                                                                 \n            uri: lb://pig-auth                                                                                                                                                                                                                                           \n            predicates:                                                                                                                                                                                                                                                  \n              - Path=/auth/**                                                                                                                                                                                                                                            \n          #UPMS 模块                                                                                                                                                                                                                                                     \n          - id: pig-upms-biz                                                                                                                                                                                                                                             \n            uri: lb://pig-upms-biz                                                                                                                                                                                                                                       \n            predicates:                                                                                                                                                                                                                                                  \n              - Path=/admin/**                                                                                                                                                                                                                                           \n            filters:                                                                                                                                                                                                                                                     \n              # 限流配置                                                                                                                                                                                                                                                 \n              - name: RequestRateLimiter                                                                                                                  