es:                                                                                                                                                                                                                                                  \n              - Path=/order/**                                                                                                                                                                                                                                           \n          # 资产模块                                                                                                                                                                                                                                                     \n          - id: pig-vault-biz                                                                                                                                                                                                                                            \n            uri: lb://pig-vault-biz                                                                                                                                                                                                                                      \n            predicates:                                                                                                                                                                                                                                                  \n              - Path=/vault/**                                                                                                                                                                                                                                           \n          # 代码生成模块                                                                                                                                                                                                                                                 \n          - id: pig-codegen                                                                                                                                                                                                                                              \n            uri: lb://pig-codegen                                                                                                                                                                                                                                        \n            predicates:                                                                                                                                                                                                                                                  \n              - Path=/gen/**                                                                                                                                                                                                                                             \n          # 定时任务模块                                                                                                                                                                                                                                                 \n          - id: pig-quartz                                                                                                                                                                                                                                               \n            uri: lb://pig-quartz                                                                                                                                                                                                                                         \n            predicates:        