                                                                                            \n              - RewritePath=/v3/api-docs/(?<path>.*), /$\\{path}/$\\{path}/v3/api-docs                                                                                                                                                                                                                                                               \n        server:                                                                                                                                                                                                                                                              \n          webflux:                                                                                                                                                                                                                                                           \n            globalcors:                                                                                                                                                                                                                                                      \n              add-to-simple-url-handler-mapping: true                                                                                                                                                                                                                        \n              cors-configurations:                                                                                                                                                                                                                                           \n                \'[/**]\':                                                                                                                                                                                                                                                     \n                  allowedOriginPatterns:   # ✅ 改为具体的patterns\n                    - \"http://localhost:*\"\n                    - \"http://127.0.0.1:*\"\n                    - \"http://192.168.*:*\"                                                                                                                                                                                                                           \n                  allowedMethods: \"*\"                                                                                                                                                                                                                                        \n                  allowedHeaders: \"*\"                                                                                                                                                                                                                                        \n                  allowCredentials: true                                                                                                                                                                                                                                     \n                  maxAge: 3600                                                                                                                                                                                                                                               \n            ','078327505a971fed9a5cf928ed3940b6','2025-01-30 16:50:04','2026-01-23 09:21:32','nacos','192.168.155.1','','public','',NULL,NULL,'yaml',NULL,''),(5,'pig-monitor-dev.yml','DEFAULT_GROUP','spring:\n  autoconfigure:\n    exclude: com.pig4cloud.pig.common.core.config.JacksonConfiguration\n  # 安全配置\n  security:\n    user:\n      name: ENC(8Hk2ILNJM8UTOuW/Xi75qg==)     # pig\n      password: ENC(o6cuPFfUevmTbkmBnE67Ow