                          \n            uri: lb://pig-quartz                                                                                                                                                                                                                                         \n            predicates:                                                                                                                                                                                                                                                  \n              - Path=/job/**                                                                                                                                                                                                                                             \n          # 固定路由转发配置 无修改                                                                                                                                                                                                                                      \n          - id: openapi                                                                                                                                                                                                                                                  \n            uri: lb://pig-gateway                                                                                                                                                                                                                                        \n            predicates:                                                                                                                                                                                                                                                  \n              - Path=/v3/api-docs/**                                                                                                                                                                                                                                     \n            filters:                                                                                                                                                                                                                                                     \n              - RewritePath=/v3/api-docs/(?<path>.*), /$\\{path}/$\\{path}/v3/api-docs                                                                                                                                                                                                                                                               \n        server:                                                                                                                                                                                                                                                              \n          webflux:                                                                                                                                                                                                                                                           \n            globalcors:                                                                                                                                                                                                                                                      \n              add-to-simple-url-handler-mapping: true                                                                                                                                                                                                                        \n              cors-configurations:                                                                                                                                                                                                                                           \n                \'[/**]\':                                                                                                                                                                                                                                                     \n                  allowedOriginPatterns:   # ✅ 改为具体的patterns\n                    - \"http://localhost:*\"\n                    - \"http://127.0.0.1:*\"\n                    - \"http://192.168.*:*\"                                                                                                                                                                                                                           \n                  allowedMethods: \"*\"                                                                                                                                                                                                                                        \n                  allowedHeaders: \"*\"                                                                                                                                                                                                                                        \n                  allowCredentials: true                                                                                                                                                                                                                                     \n                  maxAge: 3600                                                                                                                                                                                                                                               \n            ','078327505a971fed9a5cf928ed3940b6','2026-01-22 17:47:37','2026-01-23 09:21:32','nacos_na