                                                                                                                                                                                                                      \n              - name: RequestRateLimiter                                                                                                                                                                                                                                 \n                args:                                                                                                                                                                                                                                                    \n                  key-resolver: \'#{@remoteAddrKeyResolver}\'                                                                                                                                                                                                              \n                  redis-rate-limiter.replenishRate: 100                                                                                                                                                                                                                  \n                  redis-rate-limiter.burstCapacity: 200                                                                                                                                                                                                                  \n          # 订单模块                                                                                                                                                                                                                                                     \n          - id: pig-order-biz                                                                                                                                                                                                                                            \n            uri: lb://pig-order-biz                                                                                                                                                                                                                                      \n            predicates:                                                                                                                                                                                                                                                  \n              - Path=/order/**                                                                                                                                                                                                                                           \n          # 资产模块                                                                                                                                                                                                                                                     \n          - id: pig-vault-biz                                                                                                                                                                                                                                            \n            uri: lb://pig-vault-biz                                                                                                                                                                                                                                      \n            predicates:                                                                                                                                                                                                                                                  \n              - Path=/vault/**                                                                                                                                                                                                                                           \n          # 代码生成模块                                                                                                                                                                                                                                                 \n          - id: pig-codegen                                                                                                                                                                                                                                              \n            uri: lb://pig-codegen                                                                                                                                                                                                                                        \n            predicates:                                                                                                                                                                                                                                                  \n              - Path=/gen/**                                                                                                                                                                                                                                             \n          # 定时任务模块                                                                                                                                                                                                                                                 \n          - id: pig-quartz                                                                                                                                                                                                                                               \n            uri: lb://pig-quartz                                                                                                                                                                                                                                         \n            predicates:                                                                                                                                                                                                                                                  \n              - Path=/job/**                                                                                                                                                                                                                                             \n          # 固定路由转发配置 无修改                                                                                                                                                                                                                                      \n          - id: openapi                                                                                                                                                                                                                                                  \n            uri: lb://pig-gateway                                                                                                                                                                                                                                        \n            predicates:                                                                                                                                                                                                                                                  \n              - Path=/v3/api-docs/**                                                                                                                                                                                                                                     \n            filters:                                                                                                                                                                                                                                                     \n              - RewritePath=/v3/api-docs/(?<path>.*), /$\\{path}/$\\{path}/v3/api-docs                                                                                                                                                                                                                                                               \n        server:                                                                                                                                                                                                                                                              \n          webflux:                                                                                                                                                                                                                                                           \n            globalcors:                                                                                                                                                                                                                                                      \n              add-to-simple-url-handler-mapping: true                                                                                                                                                                                                                        \n              cors-configurations:                                                                                                                                                                                                                                           \n                \'[/**]\':                                                                                                                                                                                                                                                     \n                  allowedOriginPatterns:   # ✅ 改为具体的patterns\n                    - \"http://localhost:*\"\n                    - \"http://127.0.0.1:*\"\n                    - \"http://192.168.*:*\"                                                                                                                                                                                                                           \n                  allowedMethods: \"*\"                                                                                                                                                                                                                                        \n                  allowedHeaders: \"*\"                                                                                                                                                                                                                                        \n                  allowCredentials: true                                                                                                                                                                                                                                     \n                  maxAge: 3600                                                                                                                                                                                                                                               \n            ','ca9d48618cff10420154efd9c590819f','2026-01-23 09:21:31','2026-01-23 09:21:32','nacos','192.168.155.1','U','public','','formal','','{\"type\":\"yaml\",\"src_user\":\"nacos\"}'),(1,21,'application-dev.yml','DEFAULT_GROUP','','# 配置文件加密根密码\njasypt:\n  encryptor:\n    password: pig\n    algorithm: PBEWithMD5AndDES\n    iv-generator-classname: org.jasypt.iv.NoIvGenerator\n    \n# Spring 相关\nspring:\n  cache:\n    type: redis\n  data:\n    redis:\n      host: ${REDIS_HOST:127.0.0.1}\n      password: ${REDIS_PASSWORD:}\n      port: ${REDIS_PORT:6379}\n      database: ${REDIS_DATABASE:0}\n  cloud:\n    sentinel:\n      eager: true\n      transport:\n        dashboard: pig-sentinel:5003\n    openfeign:\n      sentinel:\n        enabled: true\n      okhttp:\n        enabled: true\n      httpclient:\n        enabled: false\n      compression:\n        request:\n          enabled: true\n        response:\n          enabled: true\n\n# 暴露监控端点\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: \"*\"  \n  endpoint:\n    health:\n      show-details: ALWAYS\n\n# mybaits-plus配置\nmybatis-plus:\n  mapper-locations: classpath:/mapper/*Mapper.xml\n  global-config:\n    banner: false\n    db-config:\n      id-type: auto\n      table-underline: true\n      logic-delete-value: 1\n      logic-not-delete-value: 0\n  type-handlers-package: com.pig4cloud.pig.common.mybatis.handler\n  configuration:\n    map-underscore-to-camel-case: true\n    shrink-whitespaces-in-sql: true\n\n# 短信插件配置：https://www.yuque.com/vxixfq/pig/zw8udk\nsms:\n  is-print: false # 是否打印日志\n  config-type: yaml # 配置类型，yaml','670b60f71ed234ee2c2d363721a1e2c9','2026-01-24 21:40:46','2026-01-24 21:40:47','nacos','192.168.155.1','U','public','','formal','','{\"type\":\"yaml\",\"src_user\":\"nacos\"}'),(1,22,'application-dev.yml','DEFAULT_GROUP','','# 配置文件加密根密码\njasypt:\n  encryptor:\n    password: pig\n    algorithm: PBEWithMD5AndDES\n    iv-generator-classname: org.jasypt.iv.NoIvGenerator\n    \n# Spring 相关\nspring:\n  cache:\n    type: redis\n  data:\n